<template>
	<div class="edit_view">
        <div class="breadcrumb-wrapper" style="width: 100%;">
            <div class="bread_view">
                <el-breadcrumb separator=">" class="breadcrumb">
                    <el-breadcrumb-item class="first_breadcrumb" :to="{ path: '/' }">首页</el-breadcrumb-item>
                    <el-breadcrumb-item class="second_breadcrumb" v-for="(item,index) in breadList" :key="index">{{item.name}}</el-breadcrumb-item>
                </el-breadcrumb>
            </div>
        </div>
		<el-form ref="formRef" :model="form" class="add_form" label-width="120px" :rules="rules">
			<el-row>
				<el-col :span="12">
					<el-form-item label="优惠券id" prop="couponId">
						<el-input class="list_inp"
                                  v-model="form.couponId"
                                  placeholder="优惠券id"
                                  type="text"
							      :readonly="!isAdd||disabledForm.couponId?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="优惠券名称" prop="couponName">
						<el-input class="list_inp"
                                  v-model="form.couponName"
                                  placeholder="优惠券名称"
                                  type="text"
							      :readonly="!isAdd||disabledForm.couponName?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="券编号" prop="couponNumber">
						<el-input class="list_inp"
                                  v-model="form.couponNumber"
                                  placeholder="券编号"
                                  type="text"
							      :readonly="!isAdd||disabledForm.couponNumber?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="优惠券类型" prop="couponType">
						<el-select
							class="list_sel"
							:disabled="!isAdd||disabledForm.couponType?true:false"
							v-model="form.couponType" 
							placeholder="请选择优惠券类型"
							style="width:100%;"
							>
							<el-option v-for="(item,index) in couponTypeLists" :label="item"
								:value="item"
								>
							</el-option>
						</el-select>
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="满额" prop="fullAmount">
						<el-input class="list_inp"
                                  v-model.number="form.fullAmount"
                                  placeholder="满额"
                                  type="number"
							      :readonly="!isAdd||disabledForm.fullAmount?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="优惠额" prop="discountAmount">
						<el-input class="list_inp"
                                  v-model.number="form.discountAmount"
                                  placeholder="优惠额"
                                  type="number"
							      :readonly="!isAdd||disabledForm.discountAmount?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="生效时间" prop="effectTime">
						<el-date-picker
							class="list_date"
							v-model="form.effectTime"
							format="YYYY-MM-DD HH:mm:ss"
							value-format="YYYY-MM-DD HH:mm:ss"
							type="datetime"
							style="width:100%;"
							:readonly="!isAdd||disabledForm.effectTime?true:false"
							placeholder="请选择生效时间" />
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="过期时间" prop="expireTime">
						<el-date-picker
							class="list_date"
							v-model="form.expireTime"
							format="YYYY-MM-DD HH:mm:ss"
							value-format="YYYY-MM-DD HH:mm:ss"
							type="datetime"
							style="width:100%;"
							:readonly="!isAdd||disabledForm.expireTime?true:false"
							placeholder="请选择过期时间" />
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="备注" prop="remark">
						<el-input class="list_inp"
                                  v-model="form.remark"
                                  placeholder="备注"
                                  type="text"
							      :readonly="!isAdd||disabledForm.remark?true:false" />
					</el-form-item>
				</el-col>

				<el-col :span="12">
					<el-form-item label="使用状态" prop="status">
						<el-select
							class="list_sel"
							:disabled="!isAdd||disabledForm.status?true:false"
							v-model="form.status" 
							placeholder="请选择使用状态"
							style="width:100%;"
							>
							<el-option v-for="(item,index) in statusLists" :label="item"
								:value="item"
								>
							</el-option>
						</el-select>
					</el-form-item>
				</el-col>
				<el-col :span="12">
					<el-form-item label="商户名称" prop="shangjiazhanghao">
						<el-input class="list_inp"
                                  v-model="form.shangjiazhanghao"
                                  placeholder="商户名称"
                                  type="text"
							      :readonly="!isAdd||disabledForm.shangjiazhanghao?true:false" />
					</el-form-item>
				</el-col>

			</el-row>
			<div class="formModel_btn_box">
				<el-button class="formModel_cancel" @click="backClick">取消</el-button>
				<el-button class="formModel_confirm"
                           @click="save"
                           type="success"
				>
					保存
				</el-button>
			</div>
		</el-form>
	</div>
</template>
<script setup>
	import {
		ref,
		getCurrentInstance,
		watch,
		onUnmounted,
		onMounted,
		nextTick,
		computed
	} from 'vue';
	import {
		useRoute,
		useRouter
	} from 'vue-router';
    import {
        useStore
    } from 'vuex';
    const store = useStore()
    const user = computed(()=>store.getters['user/session'])
    const moment = window.moment
	const context = getCurrentInstance()?.appContext.config.globalProperties;
	const route = useRoute()
	const router = useRouter()
	//基础信息
	const tableName = 'mycoupon'
	const formName = '我的优惠券'
	//基础信息
	const breadList = ref([{
		name: formName
	}])
	//获取唯一标识
	const getUUID =()=> {
      return new Date().getTime();
    }
	//form表单
	const form = ref({
		couponId: '',
		couponName: '',
		couponNumber: '',
		couponType: '',
		effectTime: '',
		expireTime: '',
		remark: '',
		status: '',
		userid: '',
		shangjiazhanghao: '',
	})
	const formRef = ref(null)
	const id = ref(0)
	const type = ref('')
	const disabledForm = ref({
		couponId : false,
		couponName : false,
		couponNumber : false,
		couponType : false,
		fullAmount : false,
		discountAmount : false,
		effectTime : false,
		expireTime : false,
		remark : false,
		status : false,
		userid : false,
		shangjiazhanghao : false,
	})
	const isAdd = ref(false)
	//表单验证
	const rules = ref({
		couponId: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		couponName: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		couponNumber: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		couponType: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		fullAmount: [
			{ validator: context.$toolUtil.validator.number, trigger: 'blur' },
		],
		discountAmount: [
			{ validator: context.$toolUtil.validator.number, trigger: 'blur' },
		],
		effectTime: [
		],
		expireTime: [
		],
		remark: [
		],
		status: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		userid: [
			{required: true,message: '请输入',trigger: 'blur'}, 
		],
		shangjiazhanghao: [
		],
	})
	//优惠券类型列表
	const couponTypeLists = ref([])
	//使用状态列表
	const statusLists = ref([])
	//获取info
	const getInfo = ()=>{
		context?.$http({
			url: `${tableName}/info/${id.value}`,
			method: 'get'
		}).then(res => {
			let reg=new RegExp('../../../file','g')
			form.value = res.data.data
		})
	}
	const crossRow = ref('')
	const crossTable = ref('')
	const crossTips = ref('')
	const crossColumnName = ref('')
	const crossColumnValue = ref('')
	//初始化
	const init = (formId=null,formType='add',formNames='',row=null,table=null,statusColumnName=null,tips=null,statusColumnValue=null) => {
		if(formId){
			id.value = formId
			type.value = formType
		}
		if(formType == 'add'){
			isAdd.value = true
		}else if(formType == 'info'){
			isAdd.value = false
			getInfo()
		}else if(formType == 'edit'){
			isAdd.value = true
			getInfo()
		}
		else if(formType == 'cross'){
			isAdd.value = true
			// getInfo()
			for(let x in row){
				if(x=='couponId'){
					form.value.couponId = row[x];
					disabledForm.value.couponId = true;
					continue;
				}
				if(x=='couponName'){
					form.value.couponName = row[x];
					disabledForm.value.couponName = true;
					continue;
				}
				if(x=='couponNumber'){
					form.value.couponNumber = row[x];
					disabledForm.value.couponNumber = true;
					continue;
				}
				if(x=='couponType'){
					form.value.couponType = row[x];
					disabledForm.value.couponType = true;
					continue;
				}
				if(x=='fullAmount'){
					form.value.fullAmount = row[x];
					disabledForm.value.fullAmount = true;
					continue;
				}
				if(x=='discountAmount'){
					form.value.discountAmount = row[x];
					disabledForm.value.discountAmount = true;
					continue;
				}
				if(x=='effectTime'){
					form.value.effectTime = row[x];
					disabledForm.value.effectTime = true;
					continue;
				}
				if(x=='expireTime'){
					form.value.expireTime = row[x];
					disabledForm.value.expireTime = true;
					continue;
				}
				if(x=='remark'){
					form.value.remark = row[x];
					disabledForm.value.remark = true;
					continue;
				}
				if(x=='status'){
					form.value.status = row[x];
					disabledForm.value.status = true;
					continue;
				}
				if(x=='userid'){
					form.value.userid = row[x];
					disabledForm.value.userid = true;
					continue;
				}
				if(x=='shangjiazhanghao'){
					form.value.shangjiazhanghao = row[x];
					disabledForm.value.shangjiazhanghao = true;
					continue;
				}
			}
			if(row){
				crossRow.value = row
			}
			if(table){
				crossTable.value = table
			}
			if(tips){
				crossTips.value = tips
			}
			if(statusColumnName){
				crossColumnName.value = statusColumnName
			}
			if(statusColumnValue){
				crossColumnValue.value = statusColumnValue
			}
		}
		couponTypeLists.value = "满减券".split(',')
		statusLists.value = "可使用,已使用,已过期".split(',')
	}
	//初始化
	//取消
	const backClick = () => {
		history.back()
	}
	//提交
	const save=()=>{
		var table = crossTable.value
		var objcross = JSON.parse(JSON.stringify(crossRow.value))
		let crossUserId = ''
		let crossRefId = ''
		let crossOptNum = ''
		formRef.value.validate(async (valid)=>{
			if(valid){
                if(type.value == 'cross'){
                    if(crossColumnName.value!=''){
                        if(!crossColumnName.value.startsWith('[')){
                            for(let o in objcross){
                                if(o == crossColumnName.value){
                                    objcross[o] = crossColumnValue.value
                                }
                            }
                            //修改跨表数据
                            await changeCrossData(objcross)
                        }else{
                            crossUserId = context?.$toolUtil.storageGet('userid')
                            crossRefId = objcross['id']
                            crossOptNum = crossColumnName.value.replace(/\[/,"").replace(/\]/,"")
                        }
                    }
                }
				if(crossUserId&&crossRefId){    //限制用户操作次数
					form.value.crossuserid = crossUserId
					form.value.crossrefid = crossRefId
					let params = {
						page: 1,
						limit: 1000, 
						crossuserid:form.value.crossuserid,
						crossrefid:form.value.crossrefid,
					}
					context?.$http({
						url: `${tableName}/page`,
						method: 'get', 
						params: params 
					}).then(async (res)=>{
						if(res.data.data.total>=crossOptNum){
							context?.$toolUtil.message(`${crossTips.value}`,'error')
							return false
						}else{
							context?.$http({
								url: `${tableName}/${!form.value.id ? "save" : "update"}`,
								method: 'post', 
								data: form.value 
							}).then(async (res)=>{
                                context?.$toolUtil.message(`操作成功`,'success')
                                history.back()
							})
						}
					})
				}else{
					context?.$http({
						url: `${tableName}/${!form.value.id ? "save" : "update"}`,
						method: 'post', 
						data: form.value 
					}).then(async (res)=>{
                        context?.$toolUtil.message(`操作成功`,'success')
                        history.back()
					})
				}
			}
		})
	}
	//修改跨表数据
	const changeCrossData=(row,key)=>{
        if(type.value == 'cross'){
            let data = row
            if(key){	//如果有指定key，则只更新key属性
                data = {
                    id:row.id,
                }
                data[key] = row[key]
            }
            context?.$http({
                url: `${crossTable.value}/update`,
                method: 'post',
                data: data
            }).then(res=>{})
        }
	}
	onMounted(()=>{
		type.value = route.query.type?route.query.type:'add'
		let row = null
		let table = null
		let statusColumnName = null
		let tips = null
		let statusColumnValue = null
		if(type.value == 'cross'){
			row = context?.$toolUtil.storageGet('crossObj')?JSON.parse(context?.$toolUtil.storageGet('crossObj')):{}
			table = context?.$toolUtil.storageGet('crossTable')
			statusColumnName = context?.$toolUtil.storageGet('crossStatusColumnName')
			tips = context?.$toolUtil.storageGet('crossTips')
			statusColumnValue = context?.$toolUtil.storageGet('crossStatusColumnValue')
		}
		init(route.query.id?route.query.id:null, type.value,'', row, table, statusColumnName, tips, statusColumnValue)
	})
    onUnmounted(()=>{
        Object.keys(localStorage).map(item=>{
            if(item.startsWith('cross')){
                localStorage.removeItem(item)
            }
        })
    })
</script>
<style lang="scss" scoped>
	// 表单
	.add_form{
		// form item
		:deep(.el-form-item) {
			// 内容盒子
			.el-form-item__content {
			}
		}
	}
</style>
<style lang="scss">
.edit_view {
    width: 100%;
    padding: 0 7%;
    margin: 0 auto;
    position: relative;
    font-size:16px;
    color:#666;
}
.edit_view .add_form{
    width: 100%;
    margin: 30px auto;
    background: rgb(255, 255, 255);
    padding: 50px 100px;
    border:0px solid #eee;
    border-radius: 12px;
    box-shadow:0px 4px 6px -3px #999;
}


.edit_view .add_form .el-form-item .el-form-item__content{
    display: flex;
    justify-content: flex-start;
    align-items: center;
    flex-wrap: wrap;
    width: calc(100% - 120px);
}
.edit_view .list_inp .el-input__wrapper{
    height: 36px;
}

.edit_view .add_form .el-form-item .el-form-item__content .list_sel{
    line-height: 36px;
    
    box-sizing: border-box;
    width: calc(100% - 120px);
    padding: 0px 10px;
    border-radius: 0px;
    background: rgb(255, 255, 255);
    font-size: 16px;
}

.edit_view .list_date{
    line-height: 36px;
}








</style>